In this post, a webapp book template is demonstrated.
<!DOCTYPE>
<html>
<head></head>
<body>
<div class="javascript_css"></div>
<script>
function functionName() { var frontpage = [];
var backpage = [];
for (var i=0; i<5; i++) {
var pElement = document.createElement("p");
pElement.setAttribute("id", "p"+i);
pElement.setAttribute("class", "p_simple");
pElement.setAttribute("onclick", "processEvent_click(this.id)");
pElement.style.position = "absolute";
pElement.style.top = "60px";
pElement.style.width = "100px";
pElement.style.height = "200px";
pElement.style.zIndex = `${10-i}`;
pElement.style.backgroundColor = (i == 0) ? "hsl(120 100% 90%)" : `hsl(60 100% ${70+(5*i)}%)`;
pElement.style.border = "1px solid gray";
pElement.style.perspective = "300px";
pElement.style.transformStyle = "preserve-3d";
pElement.style.transform = `skewX(-10deg) translateX(${100+(5*i)}px) translateX(${5*i}px)`;
pElement.style.transformOrigin = "bottom right";
pElement.style.fontSize = (i == 0) ? "14px" : "12px";
pElement.innerText = (i == 0) ? "title": `frontpage ${i}`;
document.getElementsByClassName("javascript_css")[0].appendChild(pElement);
frontpage.push(pElement.innerText);
backpage.push("backpage"+i);
}
document.getElementById("p0").frontpage = frontpage;
document.getElementById("p0").backpage = backpage;
}
function processEvent_click(this_id) {
var num = Number(this_id.split("p")[1]);
if (document.getElementById(this_id).style.zIndex == "10" && document.getElementById(this_id).innerText != "title") {
// flip back.
var translateX = Number(document.getElementById(this_id).style.transform.split("translateX(")[1].split("px)")[0]);
var width = Number(document.getElementById(this_id).style.width.split("px")[0]);
document.getElementById(this_id).style.transform = `${document.getElementById(this_id).style.transform} translateX(${translateX}px)`;
document.getElementById(this_id).style.zIndex = 10-Number(this_id.split("p")[1]);
// Page text.
document.getElementById(this_id).innerText = document.getElementById("p0").frontpage.at(num);
} else {
var translateX = Number(document.getElementById(this_id).style.transform.split("translateX(")[1].split("px)")[0]);
var width = Number(document.getElementById(this_id).style.width.split("px")[0]);
document.getElementById(this_id).style.transform = `${document.getElementById(this_id).style.transform} translateX(${-translateX}px)`;
document.getElementById(this_id).style.zIndex = "10";
// page text.
document.getElementById(this_id).innerText = document.getElementById("p0").backpage.at(num);
}
}
</script>
<script>
topbar();
function topbar() {
document.getElementsByClassName("javascript_css")[0].style.position = "absolute";
document.getElementsByClassName("javascript_css")[0].style.width = "300px";
document.getElementsByClassName("javascript_css")[0].style.height = "50px";
document.getElementsByClassName("javascript_css")[0].style.border = "1px solid gray";
document.getElementsByClassName("javascript_css")[0].style.borderRadius = "2px";
document.getElementsByClassName("javascript_css")[0].innerHTML = "Book.";
functionName();
}
</script>
</body>
</html>
